// worker_threads worker for video-deblur. The orchestrator (video-deblur.ts)
// spawns N of these and round-robins frames onto them. Each worker holds its
// own deblur config (width, height, options) after init, then processes
// frames stamped with a sequence number so the orchestrator can write them
// out in input order regardless of which worker finished first. Frame
// buffers are transferable ArrayBuffers — no memcpy across thread
// boundaries.
//
// Message protocol (locked contract — orchestrator depends on this):
//
//   Inbound (orchestrator -> worker):
//     { type: 'init';     width: number; height: number; options: any }
//     { type: 'process';  seq: number; frame: ArrayBuffer /* w*h*3 RGB24 */ }
//     { type: 'shutdown' }
//
//   Outbound (worker -> orchestrator):
//     { type: 'ready' }
//     { type: 'done';  seq: number; recovered: ArrayBuffer /* w*h*3 RGB24 */; selectedSigma: number }
//     { type: 'error'; seq: number; error: string }
//
// The recovered ArrayBuffer is transferred (zero-copy) via the second arg
// to parentPort.postMessage.

import { parentPort } from 'node:worker_threads';
import { deblurAnyImage } from './deblur-any-image';
import { floatPlaneToUint8Clamped } from './invisible-watermark';

if (!parentPort) {
  throw new Error('video-frame-worker: must be loaded as a worker_threads worker');
}

let cfg: { width: number; height: number; options: any } | null = null;

parentPort.on('message', async (msg: any) => {
  if (!msg || typeof msg !== 'object' || typeof msg.type !== 'string') {
    return;
  }

  if (msg.type === 'init') {
    if (typeof msg.width !== 'number' || typeof msg.height !== 'number') {
      return;
    }
    cfg = { width: msg.width, height: msg.height, options: msg.options };
    return;
  }

  if (msg.type === 'shutdown') {
    process.exit(0);
  }

  if (msg.type === 'process') {
    const seq: number = typeof msg.seq === 'number' ? msg.seq : -1;

    if (cfg === null) {
      const err = new RangeError('video-frame-worker: process received before init');
      parentPort!.postMessage({ type: 'error', seq, error: String(err) });
      throw err;
    }

    try {
      if (!(msg.frame instanceof ArrayBuffer)) {
        throw new TypeError('video-frame-worker: process.frame must be an ArrayBuffer');
      }

      const expected = cfg.width * cfg.height * 3;
      if (msg.frame.byteLength !== expected) {
        throw new RangeError(
          `video-frame-worker: frame byteLength ${msg.frame.byteLength} !== width*height*3 ${expected}`,
        );
      }

      const inU8 = new Uint8Array(msg.frame);

      const result: any = await deblurAnyImage(
        { data: inU8, width: cfg.width, height: cfg.height, channels: 3 },
        { ...cfg.options, watermarkFrameIndex: seq },
      );

      const recovered: Float32Array = result.recovered;
      const selectedSigma: number = result.selectedSigma;

      const u8 = floatPlaneToUint8Clamped(recovered);
      const recoveredBuffer = toOwnedArrayBuffer(u8);

      parentPort!.postMessage(
        { type: 'done', seq, recovered: recoveredBuffer, selectedSigma },
        [recoveredBuffer],
      );
    } catch (err) {
      parentPort!.postMessage({ type: 'error', seq, error: String(err) });
    }
    return;
  }
});

parentPort.postMessage({ type: 'ready' });

function toOwnedArrayBuffer(bytes: Uint8Array): ArrayBuffer {
  const out = new ArrayBuffer(bytes.byteLength);
  new Uint8Array(out).set(bytes);
  return out;
}
